commit c986b8dee31a2c12b34e40f0ea3f27a88af7b4e1
Author: Bartłomiej Dach <dach.bartlomiej@gmail.com>
Date:   Wed May 21 13:38:11 2025 +0200

    Fix passthrough input manager mouse position being desynced from parent on first frame

    Assume a parenting `InputManager` A and a child
    `PassThroughInputManager` B.

    On the first frame where B is a child of A, the following sequence of
    events occurs:

    1. `InputManager` is a `CompositeDrawable`. `CompositeDrawable`s update
       themselves before updating children. As such, A updates itself first.
    2. As part of its update logic, A grabs all pending inputs to be
       processed.
    3. The collected pending inputs are "applied to current state". The
       process of "applying to current state" is equivalent to passing the
       input to the appropriate input queue in order, until a drawable
       handles the input.
    4. While B at this point is a child of A, it is not yet
       `LoadState.Loaded`, because `LoadComplete()` runs as part of the
       first `UpdateSubTree()` call on B, which is yet to occur. Therefore,
       B is omitted from any potentially relevant input queues.
    5. Having completed updating itself, A updates its children.
    6. As part of that children update, B's `UpdateSubTree()` is called, and
       with it, its `LoadComplete()`.
    7. `InputManager.LoadComplete()` has this:

            https://github.com/ppy/osu-framework/blob/576c99b7369432af8d4e6860ac59478e78b5bb48/osu.Framework/Input/InputManager.cs#L184-L186

       which means that not only did it not sync its mouse position with the
       parent even if it has `UseParentInput == true`, it can *actively* use
       a completely different non-zero position due to the aforementioned
       operation.

    While all this corrects in the next frame, the entire aforementioned
    sequence still means that for the first frame of operation, B will have
    a mouse position completely desynced from A, even if it specifies
    `UseParentInput == true`.

    Because of the aforementioned fact that `CompositeDrawable`s update
    themselves before updating children, this allows the *children* to read
    the bogus mouse position, too. One such child may be a *replay
    recorder*, for instance, thus causing
    https://github.com/ppy/osu/issues/28384.

    The proposed fix here is a forced synchronisation of mouse position with
    the parent on every frame via `Update()`. As, again,
    `CompositeDrawable`s update themselves before children, this is
    sufficient to avoid exposing the invalid position anywhere lower down.
---
 osu.Framework/Input/PassThroughInputManager.cs | 35 +++++++++++++++++---------
 1 file changed, 23 insertions(+), 12 deletions(-)

diff --git a/osu.Framework/Input/PassThroughInputManager.cs b/osu.Framework/Input/PassThroughInputManager.cs
index df415debe..d531c55fe 100644
--- a/osu.Framework/Input/PassThroughInputManager.cs
+++ b/osu.Framework/Input/PassThroughInputManager.cs
@@ -43,10 +43,7 @@ public virtual bool UseParentInput
                 useParentInput = value;

                 if (UseParentInput)
-                {
-                    syncReleasedInputs();
-                    syncJoystickAxes();
-                }
+                    syncWithParent();
             }
         }

@@ -209,15 +206,21 @@ protected override void Update()

             // There are scenarios wherein we cannot receive the release events of pressed inputs. For simplicity, sync every frame.
             if (UseParentInput)
-            {
-                syncReleasedInputs();
-                syncJoystickAxes();
-            }
+                syncWithParent();
         }

         /// <summary>
-        /// Updates state of any buttons that have been released by parent while <see cref="UseParentInput"/> was disabled.
+        /// Synchronises <see cref="InputManager.CurrentState"/> with the parent input manager
+        /// to catch up with any changes that occurred since <see cref="UseParentInput"/> was disabled,
+        /// or to set our initial state such that it matches the parent input manager.
         /// </summary>
+        private void syncWithParent()
+        {
+            syncReleasedInputs();
+            syncJoystickAxes();
+            syncMousePosition();
+        }
+
         private void syncReleasedInputs()
         {
             if (parentInputManager == null)
@@ -248,9 +251,6 @@ private void syncReleasedInputs()
                 new TabletAuxiliaryButtonInput(button, false).Apply(CurrentState, this);
         }

-        /// <summary>
-        /// Updates state of joystick axes that have changed values while <see cref="UseParentInput"/> was disabled.
-        /// </summary>
         private void syncJoystickAxes()
         {
             if (parentInputManager == null)
@@ -269,5 +269,16 @@ private void syncJoystickAxes()
                 }
             }
         }
+
+        private void syncMousePosition()
+        {
+            if (parentInputManager == null)
+                return;
+
+            var parentMousePosition = parentInputManager.CurrentState.Mouse.Position;
+
+            if (parentMousePosition != CurrentState.Mouse.Position)
+                new MousePositionAbsoluteInput { Position = parentMousePosition }.Apply(CurrentState, this);
+        }
     }
 }

