commit f9ef63e4f51e6d55ba5f88340adb1f7d3e5681e3
Author: Susko3 <Susko3@protonmail.com>
Date:   Wed Jan 8 16:01:56 2025 +0000

    Add support for passing through pen inputs

    `syncReleasedInputs()` is not changed as the only difference is the MouseButtonInput/TabletPenInput for left click.

    Also, it's impossible to tell what caused the left click release in the parent state (we could check
    `parentState.Mouse.LastSource`, but it could have been set from a later event).
---
 osu.Framework/Input/PassThroughInputManager.cs | 18 ++++++++++++++++++
 1 file changed, 18 insertions(+)

diff --git a/osu.Framework/Input/PassThroughInputManager.cs b/osu.Framework/Input/PassThroughInputManager.cs
index 82cce921e..0db4ef931 100644
--- a/osu.Framework/Input/PassThroughInputManager.cs
+++ b/osu.Framework/Input/PassThroughInputManager.cs
@@ -4,6 +4,7 @@
 using System;
 using System.Collections.Generic;
 using System.Linq;
+using NUnit.Framework;
 using osu.Framework.Graphics;
 using osu.Framework.Input.Events;
 using osu.Framework.Input.StateChanges;
@@ -99,16 +100,33 @@ protected override bool Handle(UIEvent e)
             if (e is MouseEvent && e.CurrentState.Mouse.LastSource is ISourcedFromTouch)
                 return false;

+            var penInput = e.CurrentState.Mouse.LastSource as ITabletPenInput;
+
             switch (e)
             {
+                case MouseDownEvent penDown when penInput != null:
+                    Assert.That(penDown.Button == MouseButton.Left);
+                    new TabletPenInput(true) { DeviceType = penInput.DeviceType }.Apply(CurrentState, this);
+                    break;
+
                 case MouseDownEvent mouseDown:
                     new MouseButtonInput(mouseDown.Button, true).Apply(CurrentState, this);
                     break;

+                case MouseUpEvent penUp when penInput != null:
+                    Assert.That(penUp.Button == MouseButton.Left);
+                    new TabletPenInput(false) { DeviceType = penInput.DeviceType }.Apply(CurrentState, this);
+                    break;
+
                 case MouseUpEvent mouseUp:
                     new MouseButtonInput(mouseUp.Button, false).Apply(CurrentState, this);
                     break;

+                case MouseMoveEvent penMove when penInput != null:
+                    if (penMove.ScreenSpaceMousePosition != CurrentState.Mouse.Position)
+                        new TabletPenPositionAbsoluteInput { Position = penMove.ScreenSpaceMousePosition, DeviceType = penInput.DeviceType }.Apply(CurrentState, this);
+                    break;
+
                 case MouseMoveEvent mouseMove:
                     if (mouseMove.ScreenSpaceMousePosition != CurrentState.Mouse.Position)
                         new MousePositionAbsoluteInput { Position = mouseMove.ScreenSpaceMousePosition }.Apply(CurrentState, this);

